def build_authn_request(destination, issuer, acs_url, name_id, email):
    request_id = "_" + str(uuid.uuid4())
    issue_instant = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
    xml = (
        '<?xml version="1.0" encoding="UTF-8"?>'
        '<samlp:AuthnRequest '
        'xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" '
        'xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" '
        f'ID="{request_id}" '
        'Version="2.0" '
        f'IssueInstant="{issue_instant}" '
        f'Destination="{destination}" '
        f'AssertionConsumerServiceURL="{acs_url}">'
        f'<saml:Issuer>{issuer}</saml:Issuer>'
        '<saml:Subject>'
        f'<saml:NameID>{name_id}</saml:NameID>'
        '<saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer"/>'
        '</saml:Subject>'
        '<samlp:NameIDPolicy AllowCreate="true"/>'
        '<samlp:RequestedAuthnContext Comparison="exact">'
        '<saml:AuthnContextClassRef>'
        'urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport'
        '</saml:AuthnContextClassRef>'
        '</samlp:RequestedAuthnContext>'
        '<saml:Extensions>'
        f'<UserEmail>{email}</UserEmail>'
        '</saml:Extensions>'
        '</samlp:AuthnRequest>'
    )
    return base64.b64encode(xml.encode("utf-8")).decode("ascii")

@app.route("/sso", methods=["GET", "POST"])
def sso():
    destination = request.values.get("destination", "")
    issuer = request.values.get("issuer", "custom-sp")
